import { describe, expect, test } from '@a0n/gnosis/test';
import { readGnosisFixture, resolveGnosisFixturePath } from '@a0n/gnosis/test';

describe('Gnosis fixture resolution', () => {
  test('resolves direct package fixtures relative to the calling module', () => {
    const fixturePath = resolveGnosisFixturePath(
      '../../betti.gg',
      import.meta.url
    );

    expect(fixturePath).toMatch(/open-source\/gnosis\/betti\.gg$/);
  });

  test('falls back to the canonical topology corpus for legacy root aliases', () => {
    const engineSuiteUrl = new URL(
      '../runtime/engine.test.ts',
      import.meta.url
    );
    const fixturePath = resolveGnosisFixturePath(
      '../../closed_variant.gg',
      engineSuiteUrl
    );

    expect(fixturePath).toMatch(
      /open-source\/gnosis\/topologies\/services\/closed_variant\.gg$/
    );
    expect(
      readGnosisFixture('../../structured_race.gg', engineSuiteUrl)
    ).toMatch('fast-path');
  });
});
